.darma-loader-darma-custom-607 {color: var(--loader-color, #db2777);
   width: 82px;
   aspect-ratio: 1;
   padding: 10px;
   box-sizing: border-box;
   display: grid;
   background: currentColor;
   filter: blur(5px) contrast(10) hue-rotate(180deg);
   mix-blend-mode: darken;
}
.darma-loader-darma-custom-607:before, .darma-loader-darma-custom-607:after  {
  content: "";
   grid-area: 1/1;
   margin: 30px 0;
   border-radius: 100px;
   background: #ff00ff;
   animation: darma-loader-darma-custom-607-l4 2s infinite linear;
}
.darma-loader-darma-custom-607:after  {
  --s:-1;
}
@keyframes darma-loader-darma-custom-607-l4 {
  100% {transform: rotate(calc(var(--s,1)*1turn))}
}

